/**
 * @name Dynamic class loading with user-controlled input
 * @description Finds Class.forName() or ClassLoader.loadClass() with potentially user-controlled class names
 * @kind problem
 * @problem.severity error
 * @id java/dynamic-class-loading
 * @tags security
 *       external/cwe/cwe-470
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module DynClassLoadConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("forName") and
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class")
        or
        mc.getMethod().hasName("loadClass") and
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module DynClassLoadFlow = TaintTracking::Global<DynClassLoadConfig>;

from DataFlow::Node source, DataFlow::Node sink
where DynClassLoadFlow::flow(source, sink)
select sink, "Dynamic class loading with potentially user-controlled input flowing from $@.", source, "this source"

/**
 * @name Unsafe deserialization via ObjectInputStream
 * @description ObjectInputStream.readObject() called on untrusted data
 * @kind problem
 * @problem.severity error
 * @id java/unsafe-deserialization-ois
 * @tags security
 *       external/cwe/cwe-502
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module DeserConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("readObject") or
        mc.getMethod().hasName("readUnshared")
      ) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "ObjectInputStream") and
      sink.asExpr() = mc.getQualifier()
    )
    or
    exists(ClassInstanceExpr cie |
      cie.getConstructor().getDeclaringType().hasQualifiedName("java.io", "ObjectInputStream") and
      sink.asExpr() = cie.getArgument(0)
    )
  }
}

module DeserFlow = TaintTracking::Global<DeserConfig>;

from DataFlow::Node source, DataFlow::Node sink
where DeserFlow::flow(source, sink)
select sink, "Unsafe deserialization from untrusted data flowing from $@.", source, "this source"

