/**
 * @name MixAll.properties2Object reflection with network data
 * @description MixAll uses reflection to set object properties - check if property values come from network
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-mixall-reflection-taint
 * @tags security
 *       external/cwe/cwe-470
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module MixAllReflectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // The Method.invoke call in MixAll
    exists(MethodCall mc |
      mc.getMethod().hasName("invoke") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang.reflect", "Method") and
      (sink.asExpr() = mc.getArgument(0) or sink.asExpr() = mc.getArgument(1))
    )
  }
}

module MixAllFlow = TaintTracking::Global<MixAllReflectionConfig>;
import MixAllFlow::PathGraph

from MixAllFlow::PathNode source, MixAllFlow::PathNode sink
where MixAllFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Reflective method invocation with tainted data from $@.", source.getNode(), "remote source"

/**
 * @name Network data flowing to Configuration.update (reflective property setting)
 * @description Network-supplied properties flowing to Configuration.update which uses MixAll reflection
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-network-to-config-update
 * @tags security
 *       external/cwe/cwe-470
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ConfigUpdateConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Configuration.update(Properties) - which calls properties2Object internally
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.common", "Configuration") and
      (mc.getMethod().hasName("update") or mc.getMethod().hasName("updateConfig")) and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module ConfigUpdateFlow = TaintTracking::Global<ConfigUpdateConfig>;
import ConfigUpdateFlow::PathGraph

from ConfigUpdateFlow::PathNode source, ConfigUpdateFlow::PathNode sink
where ConfigUpdateFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Network data flows to Configuration.update() (which uses reflection) from $@.", source.getNode(), "remote source"

/**
 * @name Remote data to string-based class loading (UPDATE_BROKER_CONFIG RCE)
 * @description Traces network bytes/properties to Class.forName or classloader - CVE-2023-33246 pattern
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-rce-update-config
 * @tags security
 *       external/cwe/cwe-470
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

// Look at how RemotingCommand body/extFields data flows to class loading
module RCEConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Data extracted from incoming RemotingCommand (broker network commands)
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getBody") or
        mc.getMethod().hasName("getExtFields") or
        mc.getMethod().hasName("decodeCommandCustomHeader") or
        mc.getMethod().hasName("getParameter") or
        mc.getMethod().hasName("getString")
      ) and
      (
        mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.remoting.protocol", "RemotingCommand") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("forName") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("loadClass") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module RCEFlow = TaintTracking::Global<RCEConfig>;
import RCEFlow::PathGraph

from RCEFlow::PathNode source, RCEFlow::PathNode sink
where RCEFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Remote data flows to dynamic class loading from $@.", source.getNode(), "network source"

/**
 * @name SnakeYAML load with file path from network data
 * @description Check if the file loaded by SnakeYAML can be influenced by network/user data
 * @kind path-problem
 * @problem.severity error
 * @id java/rocketmq-snakeyaml-tainted-path
 * @tags security
 *       external/cwe/cwe-502
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module SnakeYamlFileConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // AclUtils.getYamlDataObject or Yaml.load with a file input
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("org.yaml.snakeyaml", "Yaml") and
      (mc.getMethod().hasName("load") or mc.getMethod().hasName("loadAll") or mc.getMethod().hasName("loadAs")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("org.apache.rocketmq.acl.common", "AclUtils") and
      mc.getMethod().hasName("getYamlDataObject") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module SnakeYamlFileFlow = TaintTracking::Global<SnakeYamlFileConfig>;
import SnakeYamlFileFlow::PathGraph

from SnakeYamlFileFlow::PathNode source, SnakeYamlFileFlow::PathNode sink
where SnakeYamlFileFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Network data reaches SnakeYAML deserialization from $@.", source.getNode(), "remote source"
